SELECT FROM openplatform_v2_approval_record_t WHERE 1=1
AND status = #{status}
AND business_type IN ('api_register', 'event_register', 'callback_register')
AND business_type = #{type}
AND (applicant_name LIKE CONCAT('%', #{keyword}, '%') OR business_id IN ( SELECT id FROM openplatform_v2_api_t WHERE name_cn LIKE CONCAT('%', #{keyword}, '%') UNION SELECT id FROM openplatform_v2_event_t WHERE name_cn LIKE CONCAT('%', #{keyword}, '%') UNION SELECT id FROM openplatform_v2_callback_t WHERE name_cn LIKE CONCAT('%', #{keyword}, '%') UNION SELECT id FROM openplatform_v2_permission_t WHERE name_cn LIKE CONCAT('%', #{keyword}, '%') ))
AND applicant_id = #{applicantId}
ORDER BY create_time DESC LIMIT #{offset}, #{pageSize}

